import{_ as a,o as e,c as h,e as r}from"./app-2eca34d6.js";const d={},i=r('<h2 id="介绍" tabindex="-1"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h2><p><strong>解决一些问题的最佳实践</strong></p><p>设计模式是软件开发人员在软件开发过程中面临的一般问题的解决方案。这些解决方案是众多软件开发人员经过相当长的一段时间的试验和错误总结出来的。</p><h2 id="七大原则" tabindex="-1"><a class="header-anchor" href="#七大原则" aria-hidden="true">#</a> 七大原则</h2><ul><li>开闭原则：对扩展开发，对修改关闭</li><li>单一职责原则：对于类来说，一个类只负责一项职责</li><li>依赖倒转原则：面向接口编程，依赖抽象，而不是具体实现，减少耦合</li><li>接口隔离原则：用多个接口，细化接口，而不是使用单一的接口</li><li>里氏替换原则：继承复用的基石，对开闭原则的补充 <ul><li>子类可以扩展父类的功能，但不能修改父类原有的功能</li><li>子类可以实现父类的抽象方法，但不能覆盖原有的父类方法</li></ul></li><li>合成复用原则：尽量使用合成/聚合的方式，而不是使用继承</li><li>迪米特原则：最少知道原则，对于被依赖的类不管有多复杂，将其逻辑封装到内部，不向外部泄露信息 <ul><li>降低类与类之间的耦合性</li></ul></li></ul><h2 id="分类" tabindex="-1"><a class="header-anchor" href="#分类" aria-hidden="true">#</a> 分类</h2><ul><li>创建型：隐藏对象创建过程，通过逻辑方法进行对象的创建</li><li>结构型：关注类和对象的组合关系</li><li>行为型：关注对象之间的通信</li></ul><h2 id="创建型" tabindex="-1"><a class="header-anchor" href="#创建型" aria-hidden="true">#</a> 创建型</h2><h3 id="工厂方法模式" tabindex="-1"><a class="header-anchor" href="#工厂方法模式" aria-hidden="true">#</a> 工厂方法模式</h3><p>定义一个接口或抽象工厂类，让它的实现类来创建具体的对象，不同的工厂实现类创建不同的对象</p><p>工厂方法模式生产的对象都是同一系列的对象</p><h3 id="抽象工厂模式" tabindex="-1"><a class="header-anchor" href="#抽象工厂模式" aria-hidden="true">#</a> 抽象工厂模式</h3><p>提供了创建一系列相关或者相互依赖的对象的接口。类似公司下的产品，生产汽车，将汽车分为各个零部件进行生产：车架，车门，底盘等</p><h3 id="建造者模式" tabindex="-1"><a class="header-anchor" href="#建造者模式" aria-hidden="true">#</a> 建造者模式</h3><p>将复杂的对象的创建和属性的复制分离，创建的过程和细节我们不需要知道，只需要通过构建者去操作即可</p><h3 id="原型模式" tabindex="-1"><a class="header-anchor" href="#原型模式" aria-hidden="true">#</a> 原型模式</h3><p>用于创建重复的对象，保证创建对象的性能。原型模式是创建对象的最佳方式</p><h3 id="单例模式" tabindex="-1"><a class="header-anchor" href="#单例模式" aria-hidden="true">#</a> 单例模式</h3><h2 id="结构型" tabindex="-1"><a class="header-anchor" href="#结构型" aria-hidden="true">#</a> 结构型</h2><h3 id="适配器模式" tabindex="-1"><a class="header-anchor" href="#适配器模式" aria-hidden="true">#</a> 适配器模式</h3><h3 id="桥接模式" tabindex="-1"><a class="header-anchor" href="#桥接模式" aria-hidden="true">#</a> 桥接模式</h3><h3 id="组合模式" tabindex="-1"><a class="header-anchor" href="#组合模式" aria-hidden="true">#</a> 组合模式</h3><h3 id="装饰模式" tabindex="-1"><a class="header-anchor" href="#装饰模式" aria-hidden="true">#</a> 装饰模式</h3><h3 id="外观模式" tabindex="-1"><a class="header-anchor" href="#外观模式" aria-hidden="true">#</a> 外观模式</h3><h3 id="享元模式" tabindex="-1"><a class="header-anchor" href="#享元模式" aria-hidden="true">#</a> 享元模式</h3><h3 id="代理模式" tabindex="-1"><a class="header-anchor" href="#代理模式" aria-hidden="true">#</a> 代理模式</h3><h2 id="行为型" tabindex="-1"><a class="header-anchor" href="#行为型" aria-hidden="true">#</a> 行为型</h2><h3 id="责任链模式" tabindex="-1"><a class="header-anchor" href="#责任链模式" aria-hidden="true">#</a> 责任链模式</h3><h3 id="命令模式" tabindex="-1"><a class="header-anchor" href="#命令模式" aria-hidden="true">#</a> 命令模式</h3><h3 id="解释器模式" tabindex="-1"><a class="header-anchor" href="#解释器模式" aria-hidden="true">#</a> 解释器模式</h3><h3 id="迭代器模式" tabindex="-1"><a class="header-anchor" href="#迭代器模式" aria-hidden="true">#</a> 迭代器模式</h3><h3 id="中介者模式" tabindex="-1"><a class="header-anchor" href="#中介者模式" aria-hidden="true">#</a> 中介者模式</h3><h3 id="备忘录模式" tabindex="-1"><a class="header-anchor" href="#备忘录模式" aria-hidden="true">#</a> 备忘录模式</h3><h3 id="观察者模式" tabindex="-1"><a class="header-anchor" href="#观察者模式" aria-hidden="true">#</a> 观察者模式</h3><h3 id="状态模式" tabindex="-1"><a class="header-anchor" href="#状态模式" aria-hidden="true">#</a> 状态模式</h3><h3 id="策略模式" tabindex="-1"><a class="header-anchor" href="#策略模式" aria-hidden="true">#</a> 策略模式</h3><h3 id="访问者模式" tabindex="-1"><a class="header-anchor" href="#访问者模式" aria-hidden="true">#</a> 访问者模式</h3><h3 id="模板方法模式" tabindex="-1"><a class="header-anchor" href="#模板方法模式" aria-hidden="true">#</a> 模板方法模式</h3>',38),n=[i];function t(s,c){return e(),h("div",null,n)}const o=a(d,[["render",t],["__file","DesignPatterns.html.vue"]]);export{o as default};
